ORDER = ["001", "002", "003"]

# trim Streamlit's default chrome so the zine sits closer to full-bleed
st.markdown(
    """
    <style>
      .block-container {padding: 0.6rem 1rem 2rem 1rem; max-width: 100%;}
      header[data-testid="stHeader"] {background: transparent;}
      #MainMenu, footer {visibility: hidden;}
      iframe {border: none;}
    </style>
    """,
    unsafe_allow_html=True,
)

with st.sidebar:
    st.title("🥩 Freezer Fuel")
    st.caption("Three 7-day meal-prep zines. Same rules: high protein, freeze-friendly, nut-free, dirt cheap.")
    key = st.radio(
        "Pick a plan",
        ORDER,
        format_func=lambda k: ZINES[k]["label"],
    )
    st.caption(ZINES[key]["blurb"])
    html_bytes = base64.b64decode(ZINES[key]["b64"])
    st.download_button(
        "⬇️  Download this zine (.html)",
        data=html_bytes,
        file_name=ZINES[key]["file"],
        mime="text/html",
        use_container_width=True,
    )
    st.divider()
    st.caption(
        "Heads up: the 1,300-kcal plan (GRIT) is an aggressive cut. "
        "Eat all four meals, keep water up, and see a nutritionist if you run it more than a few weeks."
    )

html = base64.b64decode(ZINES[key]["b64"]).decode("utf-8")
components.html(html, height=ZINES[key]["height"], scrolling=True)
